section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/business-model-research.json",
  "title": "Business Model Research",
  "type": "object",
  "required": [
    "artefact_id",
    "models_compared",
    "scoring_dimensions",
    "ranked_models",
    "recommendation",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date",
      "minLength": 1
    },
    "models_compared": {
      "type": "array",
      "description": "5-10 model rows",
      "minItems": 1
    },
    "scoring_dimensions": {
      "type": "object",
      "description": "{cac, ltv, margin, churn} per model"
    },
    "ranked_models": {
      "type": "array",
      "description": "ordered top\u2192bottom with rationale",
      "minItems": 1
    },
    "recommendation": {
      "type": "string",
      "description": "chosen model + rejection reasons",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation}",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}

example.code:
{
  "owner": "ruslan@faion.net",
  "last_touched": "2026-05-23T12:00:00Z",
  "template_version": "1.1.0",
  "artefact_id": "business-model-research-2026-05-23",
  "models_compared": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "scoring_dimensions": {
    "key": "value"
  },
  "ranked_models": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "recommendation": "draft",
  "evidence": [
    {
      "source": "https://example.com/transcript/1",
      "citation": "verbatim user quote"
    }
  ]
}
